INSERT INTO policy_sources (name, url, category, description) VALUES
('FTC Negative Option Rule — Subscriptions', 'https://www.ftc.gov/legal-library/browse/rules/negative-option-rule', 'Consumer Protection', 'FTC rule regulating subscription marketing, auto-renewals, and free trial offers requiring clear terms and simple cancellation.'),
('FTC Mail Order Rule', 'https://www.ftc.gov/legal-library/browse/rules/mail-internet-or-telephone-order-merchandise-rule', 'Consumer Protection', 'FTC rule requiring merchants to ship within advertised timeframes and provide prompt refunds for order delays.'),
('FTC Textile Fiber Labeling Rules', 'https://www.ftc.gov/legal-library/browse/rules/textile-fiber-rule', 'Product Safety', 'FTC rules mandating fiber content, country of origin, and manufacturer identification on textile products.'),
('EU Digital Services Act', 'https://digital-strategy.ec.europa.eu/en/policies/digital-services-act', 'International Privacy', 'EU obligations for online platforms including content moderation, algorithmic transparency, and user rights protections.'),
('CBP E-Commerce Import Guidelines', 'https://www.cbp.gov/trade/basic-import-export/e-commerce', 'Business Compliance', 'CBP compliance guidance for cross-border e-commerce including tariff classifications and import documentation.'),
('Etsy Seller Policy', 'https://www.etsy.com/legal/sellers/', 'Platform Policy', 'Etsy marketplace standards requiring original product photography, seller service levels, and listing compliance.'),
('eBay Selling Policies', 'https://www.ebay.com/help/policies/selling-policies/selling-policies?id=4214', 'Platform Policy', 'eBay seller standards, business policies, listing requirements, and performance metrics for marketplace sellers.'),
('Walmart Marketplace Seller Policies', 'https://marketplacelearn.walmart.com/guides/Policies%20&%20standards/Account/Walmart-Marketplace-seller-retailer-policies', 'Platform Policy', 'Walmart marketplace requirements including U.S. business registration, GS1 product codes, and shipping standards.');
INSERT INTO policy_sources (name, url, category, description) VALUES
('NIST Cybersecurity Framework 2.0', 'https://csrc.nist.gov/pubs/cswp/29/the-nist-cybersecurity-framework-csf-20/final', 'Cybersecurity', 'Six core functions (Identify, Protect, Detect, Respond, Recover, Govern) for organization-wide cybersecurity risk management.'),
('NIST SP 800-171 — CUI Protection', 'https://csrc.nist.gov/pubs/sp/800/171/r3/final', 'Cybersecurity', '110 security controls for protecting Controlled Unclassified Information in nonfederal systems, required for DoD contractors.'),
('CISA Cybersecurity Guidance', 'https://www.cisa.gov/guidance', 'Cybersecurity', 'CISA operational guidance, directives, and security requirements for federal agencies and critical infrastructure.'),
('SOC 2 Trust Services Criteria', 'https://www.aicpa-cima.com/topic/audit-assurance/audit-and-assurance-greater-than-soc-2', 'Cybersecurity', 'AICPA criteria for evaluating service organization controls across Security, Availability, Processing Integrity, Confidentiality, and Privacy.'),
('ISO 27001:2022 Standard', 'https://www.iso.org/standard/27001', 'Cybersecurity', 'International standard for establishing and maintaining an information security management system.'),
('SEC Cybersecurity Disclosure Rules', 'https://www.sec.gov/newsroom/press-releases/2023-139', 'Cybersecurity', 'Rules requiring public companies to disclose cybersecurity risk management, governance, and material incidents in SEC filings.'),
('CMMC 2.0 — DoD Cybersecurity', 'https://dodcio.defense.gov/CMMC/', 'Cybersecurity', 'Three-level certification model for DoD contractors to demonstrate cybersecurity capabilities on defense contracts.'),
('FTC Safeguards Rule', 'https://www.ftc.gov/legal-library/browse/rules/safeguards-rule', 'Cybersecurity', 'FTC rule requiring financial institutions to implement MFA, encryption, continuous monitoring, and breach notification.'),
('State Breach Notification Laws', 'https://iapp.org/resources/article/state-data-breach-notification-chart', 'Cybersecurity', 'Compilation of all 50 state data breach notification laws with requirements, timelines, and notification obligations.'),
('EU DORA — Digital Operational Resilience', 'https://www.eiopa.europa.eu/digital-operational-resilience-act-dora_en', 'Cybersecurity', 'EU regulation requiring financial entities to manage ICT risks, conduct resilience testing, and report major incidents.'),
('EU NIS2 Directive', 'https://digital-strategy.ec.europa.eu/en/policies/nis2-directive', 'Cybersecurity', 'EU cybersecurity directive covering 18 critical sectors with risk management and incident reporting requirements.');
INSERT INTO policy_sources (name, url, category, description) VALUES
('DOL FLSA — Wage & Overtime Rules', 'https://www.dol.gov/agencies/whd/flsa', 'Employment Law', 'Federal minimum wage and overtime requirements defining exempt and non-exempt employee classifications.'),
('EEOC Employment Discrimination Guidance', 'https://www.eeoc.gov/regulations-and-guidelines', 'Employment Law', 'Title VII enforcement guidance covering discrimination based on race, color, religion, sex, national origin, age, and disability.'),
('OSHA Workplace Safety Standards', 'https://www.osha.gov/laws-regs', 'Employment Law', 'Mandatory workplace safety standards requiring employers to maintain hazard-free workplaces and worker protections.'),
('NLRB Rules and Guidance', 'https://www.nlrb.gov/guidance', 'Employment Law', 'National Labor Relations Act protections for workers rights to unionize, collective bargaining, and association.'),
('ADA Employment Provisions — Title I', 'https://www.eeoc.gov/statutes/titles-i-and-v-americans-disabilities-act-1990-ada', 'Employment Law', 'ADA Title I prohibiting disability discrimination and requiring reasonable accommodations for qualified employees.'),
('FMLA Regulations', 'https://www.dol.gov/agencies/whd/fmla', 'Employment Law', 'Family and Medical Leave Act providing eligible employees up to 12 weeks unpaid, job-protected leave.'),
('State Paid Leave Laws Compilation', 'https://www.dol.gov/agencies/wb/paid-leave/State-Paid-Family-Medical-Leave-Laws', 'Employment Law', 'Compilation of state-level paid family and medical leave laws with varying coverage and benefit levels.'),
('DOL Worker Classification Rule', 'https://www.federalregister.gov/documents/2024/01/10/2024-00067/employee-or-independent-contractor-classification-under-the-fair-labor-standards-act', 'Employment Law', 'Six-factor economic reality test for determining employee vs. independent contractor status under FLSA.'),
('FTC Non-Compete Ban Rule', 'https://www.ftc.gov/news-events/news/press-releases/2024/04/ftc-announces-rule-banning-noncompetes', 'Employment Law', 'FTC rule banning most non-compete agreements for all workers including independent contractors.'),
('E-Verify & I-9 Compliance', 'https://www.uscis.gov/i-9', 'Employment Law', 'USCIS employment eligibility verification requirements including Form I-9 and E-Verify electronic confirmation.');
