('EPA Environmental Regulations', 'https://www.epa.gov/laws-regulations', 'ESG/Environmental', 'Federal environmental regulations covering air, water, hazardous waste, and environmental protection requirements.'),
('EU CSRD — Corporate Sustainability Reporting', 'https://finance.ec.europa.eu/capital-markets-union-and-financial-markets/company-reporting-and-auditing/company-reporting/corporate-sustainability-reporting_en', 'ESG/Environmental', 'EU directive requiring large companies to report ESG data per European Sustainability Reporting Standards.'),
('California Climate Accountability Acts', 'https://ww2.arb.ca.gov/our-work/programs/california-corporate-greenhouse-gas-ghg-reporting-and-climate-related-financial', 'ESG/Environmental', 'California law requiring companies with $1B+ revenue to disclose Scope 1, 2, 3 GHG emissions.'),
('GHG Protocol Standards', 'https://ghgprotocol.org/standards', 'ESG/Environmental', 'Global framework for measuring and reporting greenhouse gas emissions across Scope 1, 2, and 3.'),
('EU Taxonomy for Sustainable Activities', 'https://finance.ec.europa.eu/sustainable-finance/tools-and-standards/eu-taxonomy-sustainable-activities_en', 'ESG/Environmental', 'EU classification system defining economically sustainable activities for ESG reporting and investment.');
